// Procesar todas las tareas que llegan del nodo anterior
const allTasks = [];
const now = new Date();
// Ajustar a timezone de Colombia (UTC-5)
const colombiaOffset = -5 * 60;
const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
const colombiaTime = new Date(utc + (colombiaOffset * 60000));
const today = new Date(colombiaTime);
today.setHours(0, 0, 0, 0);

// Procesar cada item que llega del nodo anterior
for (const item of $input.all()) {
  const task = {
    title: item.json.title,
    category: item.json.category,
    priority: item.json.priority,
    isPrivate: item.json.isPrivate,
    dueDate: item.json.dueDate
  };
  allTasks.push(task);
}

console.log(`Procesadas ${allTasks.length} tareas`);

// Función para agrupar tareas por categoría
function groupByCategory(tasks) {
  return tasks.reduce((groups, task) => {
    const category = task.category || 'Sin categoría';
    if (!groups[category]) {
      groups[category] = [];
    }
    groups[category].push({
      title: task.title,
      priority: task.priority,
      isPrivate: task.isPrivate
    });
    return groups;
  }, {});
}

// Agrupar tareas por estado temporal
const overdueTasks = [];
const todayTasks = [];
const futureTasks = [];
const noDateTasks = [];

allTasks.forEach(task => {
  if (!task.dueDate) {
    noDateTasks.push(task);
    return;
  }

  const dueDate = new Date(task.dueDate);
  dueDate.setHours(0, 0, 0, 0);

  if (dueDate < today) {
    overdueTasks.push(task);
  } else if (dueDate.getTime() === today.getTime()) {
    todayTasks.push(task);
  } else {
    futureTasks.push(task);
  }
});

// Agrupar cada estado por categoría
const groupedTasks = {
  overdue: {
    count: overdueTasks.length,
    byCategory: groupByCategory(overdueTasks)
  },
  today: {
    count: todayTasks.length,
    byCategory: groupByCategory(todayTasks)
  },
  future: {
    count: futureTasks.length,
    byCategory: groupByCategory(futureTasks)
  },
  noDate: {
    count: noDateTasks.length,
    byCategory: groupByCategory(noDateTasks)
  }
};

// Estadísticas generales
const tasksByPriority = {};
allTasks.forEach(task => {
  tasksByPriority[task.priority] = (tasksByPriority[task.priority] || 0) + 1;
});

return [{
  json: {
    summary: `${allTasks.length} tareas: ${overdueTasks.length} vencidas, ${todayTasks.length} para hoy, ${futureTasks.length} futuras, ${noDateTasks.length} sin fecha`,
    totalTasks: allTasks.length,
    groupedTasks: groupedTasks,
    tasksByPriority: tasksByPriority,
    // Conteos rápidos para el AI
    overdueTasks: overdueTasks.length,
    todayTasks: todayTasks.length,
    futureTasks: futureTasks.length,
    noDateTasks: noDateTasks.length
  }
}];

