// Calcular fechas para análisis de tareas estancadas
const now = new Date();
const colombiaOffset = -5 * 60; // -5 horas en minutos
const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
const colombiaTime = new Date(utc + (colombiaOffset * 60000));

// Fecha actual
const today = new Date(colombiaTime);
today.setHours(0, 0, 0, 0);

// Fecha hace 7 días
const sevenDaysAgo = new Date(today);
sevenDaysAgo.setDate(today.getDate() - 7);

// Fecha hace 14 días (para tareas muy estancadas)
const fourteenDaysAgo = new Date(today);
fourteenDaysAgo.setDate(today.getDate() - 14);

// Fecha hace 30 días (para tareas críticas)
const thirtyDaysAgo = new Date(today);
thirtyDaysAgo.setDate(today.getDate() - 30);

return {
  todayTimestamp: today.toISOString(),
  sevenDaysAgoTimestamp: sevenDaysAgo.toISOString(),
  fourteenDaysAgoTimestamp: fourteenDaysAgo.toISOString(),
  thirtyDaysAgoTimestamp: thirtyDaysAgo.toISOString(),
  todayFormatted: today.toLocaleDateString('es-CO'),
  sevenDaysAgoFormatted: sevenDaysAgo.toLocaleDateString('es-CO'),
  fourteenDaysAgoFormatted: fourteenDaysAgo.toLocaleDateString('es-CO'),
  thirtyDaysAgoFormatted: thirtyDaysAgo.toLocaleDateString('es-CO')
};

// Procesar tareas estancadas y categorizarlas por nivel de urgencia
const allTasks = [];
const now = new Date();
const colombiaOffset = -5 * 60;
const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
const colombiaTime = new Date(utc + (colombiaOffset * 60000));
const today = new Date(colombiaTime);
today.setHours(0, 0, 0, 0);

// Procesar cada tarea
for (const item of $input.all()) {
  const task = {
    id: item.json._id || 'sin-id',
    title: item.json.title || 'Sin título',
    category: item.json.category || 'Sin categoría',
    priority: item.json.priority || 'schedule',
    createdAt: item.json.createdAt,
    dueDate: item.json.dueDate,
    isPrivate: item.json.isPrivate || false
  };
  allTasks.push(task);
}

if (allTasks.length === 0) {
  return [{
    json: {
      hasStagnantTasks: false,
      message: "¡Excelente! No tienes tareas estancadas 🎉",
      totalStagnantTasks: 0
    }
  }];
}

// Función para calcular días transcurridos
function calculateDaysStagnant(createdAt) {
  const created = new Date(createdAt);
  const diffTime = today - created;
  return Math.floor(diffTime / (1000 * 60 * 60 * 24));
}

// Categorizar tareas por nivel de estancamiento
const moderatelyStagnant = []; // 7-13 días
const highlyStagnant = []; // 14-29 días
const criticallyStagnant = []; // 30+ días

allTasks.forEach(task => {
  const daysStagnant = calculateDaysStagnant(task.createdAt);
  const taskWithDays = { ...task, daysStagnant };

  if (daysStagnant >= 30) {
    criticallyStagnant.push(taskWithDays);
  } else if (daysStagnant >= 14) {
    highlyStagnant.push(taskWithDays);
  } else if (daysStagnant >= 7) {
    moderatelyStagnant.push(taskWithDays);
  }
});

// Ordenar por días estancados (más críticas primero)
moderatelyStagnant.sort((a, b) => b.daysStagnant - a.daysStagnant);
highlyStagnant.sort((a, b) => b.daysStagnant - a.daysStagnant);
criticallyStagnant.sort((a, b) => b.daysStagnant - a.daysStagnant);

// Agrupar por categoría para insights
const tasksByCategory = {};
allTasks.forEach(task => {
  if (!tasksByCategory[task.category]) {
    tasksByCategory[task.category] = [];
  }
  tasksByCategory[task.category].push(task);
});

// Identificar la categoría más problemática
const categoryWithMostStagnant = Object.entries(tasksByCategory)
  .map(([category, tasks]) => ({ category, count: tasks.length }))
  .sort((a, b) => b.count - a.count)[0];

// Identificar tareas de alta prioridad estancadas
const highPriorityStagnant = allTasks.filter(task => task.priority === 'do');

return [{
  json: {
    hasStagnantTasks: true,
    totalStagnantTasks: allTasks.length,

    // Categorías por urgencia
    moderatelyStagnant: {
      count: moderatelyStagnant.length,
      tasks: moderatelyStagnant.slice(0, 5) // Top 5
    },
    highlyStagnant: {
      count: highlyStagnant.length,
      tasks: highlyStagnant.slice(0, 5)
    },
    criticallyStagnant: {
      count: criticallyStagnant.length,
      tasks: criticallyStagnant.slice(0, 5)
    },

    // Análisis adicional
    highPriorityStagnant: {
      count: highPriorityStagnant.length,
      tasks: highPriorityStagnant.slice(0, 3)
    },

    // Insights
    mostProblematicCategory: categoryWithMostStagnant?.category || 'N/A',
    mostProblematicCategoryCount: categoryWithMostStagnant?.count || 0,

    // Task más antigua
    oldestTask: allTasks.reduce((oldest, current) => 
      calculateDaysStagnant(current.createdAt) > calculateDaysStagnant(oldest.createdAt) 
        ? current : oldest
    ),
    oldestTaskDays: calculateDaysStagnant(
      allTasks.reduce((oldest, current) => 
        calculateDaysStagnant(current.createdAt) > calculateDaysStagnant(oldest.createdAt) 
          ? current : oldest
      ).createdAt
    ),

    // Estadísticas generales
    averageDaysStagnant: Math.round(
      allTasks.reduce((sum, task) => sum + calculateDaysStagnant(task.createdAt), 0) / allTasks.length
    )
  }
}];

